{
  "children": [
    {
      "name": "TriggerBuild",
      "purpose": "Create a new build record and run the build pipeline for a given repo and branch",
      "behavior": "Check no running build for repo+branch, create build record with status 'running', execute compile step, execute test step, package artifacts, update status to 'success' or 'failed', store logs incrementally",
      "boundary": {
        "in_scope": [
          "build record creation",
          "compile execution",
          "test execution",
          "artifact packaging",
          "status update",
          "log storage"
        ],
        "out_of_scope": [
          "status retrieval",
          "build listing",
          "build cancellation"
        ]
      },
      "preconditions": [
        "No running build for the same repo+branch"
      ],
      "postconditions": [
        "Build record created with final status",
        "Artifacts stored if successful"
      ],
      "guarantees": [
        "Only one build per repo+branch runs at a time",
        "Logs stored incrementally"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "repo",
          "type": "str",
          "description": "Repository name",
          "source": "parent input build_request.repo"
        },
        {
          "name": "branch",
          "type": "str",
          "description": "Branch name",
          "source": "parent input build_request.branch"
        },
        {
          "name": "config",
          "type": "dict",
          "description": "Build configuration",
          "source": "parent input build_request.config"
        }
      ],
      "outputs": [
        {
          "name": "build_result",
          "type": "dict",
          "description": "JSON with success, build_id, status, logs",
          "consumer": "parent"
        }
      ],
      "signature": "def TriggerBuild(repo: str, branch: str, config: dict) -> dict"
    },
    {
      "name": "CheckBuildStatus",
      "purpose": "Return the current status and logs of a specific build",
      "behavior": "Look up build by build_id in builds store, return its status and logs",
      "boundary": {
        "in_scope": [
          "build lookup",
          "status retrieval",
          "log retrieval"
        ],
        "out_of_scope": [
          "build creation",
          "build listing",
          "build cancellation"
        ]
      },
      "preconditions": [
        "Build exists"
      ],
      "postconditions": [
        "No state change"
      ],
      "guarantees": [
        "Returns current status and logs"
      ],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "build_id",
          "type": "str",
          "description": "Unique build identifier",
          "source": "parent input build_request.build_id"
        }
      ],
      "outputs": [
        {
          "name": "build_result",
          "type": "dict",
          "description": "JSON with success, build_id, status, logs",
          "consumer": "parent"
        }
      ],
      "signature": "def CheckBuildStatus(build_id: str) -> dict"
    },
    {
      "name": "ListBuilds",
      "purpose": "Return all builds filtered by optional repo, branch, or status",
      "behavior": "Query builds store with optional filters, return list of build records",
      "boundary": {
        "in_scope": [
          "build query",
          "filtering by repo/branch/status"
        ],
        "out_of_scope": [
          "build creation",
          "status retrieval for single build",
          "build cancellation"
        ]
      },
      "preconditions": [],
      "postconditions": [
        "No state change"
      ],
      "guarantees": [
        "Returns filtered list of builds"
      ],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "repo",
          "type": "Optional[str]",
          "description": "Filter by repository name",
          "source": "parent input build_request.repo (optional)"
        },
        {
          "name": "branch",
          "type": "Optional[str]",
          "description": "Filter by branch name",
          "source": "parent input build_request.branch (optional)"
        },
        {
          "name": "status",
          "type": "Optional[str]",
          "description": "Filter by build status",
          "source": "parent input build_request.status (optional)"
        }
      ],
      "outputs": [
        {
          "name": "build_result",
          "type": "dict",
          "description": "JSON with success, builds list",
          "consumer": "parent"
        }
      ],
      "signature": "def ListBuilds(repo: Optional[str] = None, branch: Optional[str] = None, status: Optional[str] = None) -> dict"
    },
    {
      "name": "CancelBuild",
      "purpose": "Stop a running build and update its status to 'cancelled'",
      "behavior": "Look up build by build_id, if status is 'running', stop the build process, update status to 'cancelled', store cancellation log; if already completed, no-op",
      "boundary": {
        "in_scope": [
          "build lookup",
          "build cancellation",
          "status update",
          "log append"
        ],
        "out_of_scope": [
          "build creation",
          "status retrieval",
          "build listing"
        ]
      },
      "preconditions": [
        "Build exists"
      ],
      "postconditions": [
        "If build was running, status changed to 'cancelled'",
        "Logs updated"
      ],
      "guarantees": [
        "Cancelling a completed build is a no-op"
      ],
      "composition_role": "mutate",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "build_id",
          "type": "str",
          "description": "Unique build identifier",
          "source": "parent input build_request.build_id"
        }
      ],
      "outputs": [
        {
          "name": "build_result",
          "type": "dict",
          "description": "JSON with success, build_id, status, logs",
          "consumer": "parent"
        }
      ],
      "signature": "def CancelBuild(build_id: str) -> dict"
    }
  ],
  "interface_preservation": {
    "parent_inputs_covered_by": {
      "build_request.repo": [
        "TriggerBuild.repo",
        "ListBuilds.repo"
      ],
      "build_request.branch": [
        "TriggerBuild.branch",
        "ListBuilds.branch"
      ],
      "build_request.config": [
        "TriggerBuild.config"
      ],
      "build_request.build_id": [
        "CheckBuildStatus.build_id",
        "CancelBuild.build_id"
      ],
      "build_request.status": [
        "ListBuilds.status"
      ]
    },
    "parent_outputs_produced_by": {
      "build_result": [
        "TriggerBuild.build_result",
        "CheckBuildStatus.build_result",
        "ListBuilds.build_result",
        "CancelBuild.build_result"
      ]
    }
  },
  "dataflow_edges": [
    {
      "from_node": "parent",
      "from_output": "build_request.repo",
      "to_node": "TriggerBuild",
      "to_input": "repo",
      "note": "when action='trigger'"
    },
    {
      "from_node": "parent",
      "from_output": "build_request.branch",
      "to_node": "TriggerBuild",
      "to_input": "branch",
      "note": "when action='trigger'"
    },
    {
      "from_node": "parent",
      "from_output": "build_request.config",
      "to_node": "TriggerBuild",
      "to_input": "config",
      "note": "when action='trigger'"
    },
    {
      "from_node": "parent",
      "from_output": "build_request.build_id",
      "to_node": "CheckBuildStatus",
      "to_input": "build_id",
      "note": "when action='status'"
    },
    {
      "from_node": "parent",
      "from_output": "build_request.repo",
      "to_node": "ListBuilds",
      "to_input": "repo",
      "note": "when action='list' and repo provided"
    },
    {
      "from_node": "parent",
      "from_output": "build_request.branch",
      "to_node": "ListBuilds",
      "to_input": "branch",
      "note": "when action='list' and branch provided"
    },
    {
      "from_node": "parent",
      "from_output": "build_request.status",
      "to_node": "ListBuilds",
      "to_input": "status",
      "note": "when action='list' and status provided"
    },
    {
      "from_node": "parent",
      "from_output": "build_request.build_id",
      "to_node": "CancelBuild",
      "to_input": "build_id",
      "note": "when action='cancel'"
    },
    {
      "from_node": "TriggerBuild",
      "from_output": "build_result",
      "to_node": "parent",
      "to_input": "build_result",
      "note": "return result"
    },
    {
      "from_node": "CheckBuildStatus",
      "from_output": "build_result",
      "to_node": "parent",
      "to_input": "build_result",
      "note": "return result"
    },
    {
      "from_node": "ListBuilds",
      "from_output": "build_result",
      "to_node": "parent",
      "to_input": "build_result",
      "note": "return result"
    },
    {
      "from_node": "CancelBuild",
      "from_output": "build_result",
      "to_node": "parent",
      "to_input": "build_result",
      "note": "return result"
    }
  ]
}
